import type { ButtonData } from "../types";

/**
 * Utility functions for Orca Components
 */

/**
 * بررسی اینکه آیا URL یک فایل تصویری است یا خیر
 */
export function isImageFile(url: string): boolean {
  const imageExtensions = [
    ".jpg",
    ".jpeg",
    ".png",
    ".gif",
    ".webp",
    ".bmp",
    ".svg",
  ];
  try {
    const urlObj = new URL(url);
    const pathname = urlObj.pathname.toLowerCase();
    return imageExtensions.some((ext) => pathname.endsWith(ext));
  } catch (e) {
    return false;
  }
}

/**
 * استخراج نام فایل از URL
 */
export function getFileNameFromUrl(url: string): string | null {
  try {
    const urlObj = new URL(url);
    const pathname = urlObj.pathname;
    const segments = pathname.split("/");
    const encodedFileName = segments.pop() || "";
    return decodeURIComponent(encodedFileName);
  } catch (e) {
    return null;
  }
}

/**
 * استخراج YouTube ID از URL
 */
export function getYouTubeId(url: string): string {
  const regExp =
    /^.*((youtu.be\/)|(v\/)|(\/u\/\w\/)|(embed\/)|(watch\?))\??v?=?([^#&?]*).*/;
  const match = url.match(regExp);
  return match && match[7].length === 11 ? match[7] : "";
}

/**
 * تبدیل نام رنگ Vuetify
 */
export function getVuetifyColor(colorName?: string): string {
  if (!colorName) return "#1976D2"; // primary blue

  // Map Vuetify color names to hex values
  const colorMap: Record<string, string> = {
    primary: "#1976D2",
    secondary: "#424242",
    success: "#4CAF50",
    info: "#2196F3",
    warning: "#FB8C00",
    error: "#FF5252",
    accent: "#82B1FF",
  };

  // If it's a Vuetify color name, return the hex value
  if (colorMap[colorName.toLowerCase()]) {
    return colorMap[colorName.toLowerCase()];
  }

  // If it's already a hex color or other valid CSS color, return it
  return colorName;
}

/**
 * گروه‌بندی دکمه‌ها بر اساس ردیف
 */
export function getGroupedButtons(buttons: ButtonData[]): ButtonData[][] {
  const rows: Record<number, ButtonData[]> = {};

  buttons.forEach((button) => {
    const row = button.row || 1;
    if (!rows[row]) {
      rows[row] = [];
    }
    rows[row].push(button);
  });

  // تبدیل به آرایه و مرتب‌سازی
  return Object.keys(rows)
    .sort((a, b) => parseInt(a) - parseInt(b))
    .map((row) => rows[parseInt(row)]);
}

/**
 * تولید ID یکتا برای container نقشه
 */
export function generateMapId(index: number): string {
  return `map-container-${index}-${Date.now()}-${Math.random()
    .toString(36)
    .substr(2, 9)}`;
}

/**
 * پاک کردن marker های orca از متن
 */
export function cleanOrcaMarkers(text: string): string {
  return text.replace(/\[orca\..*?\]/g, "").trim();
}

/**
 * بررسی اینکه آیا محتوا loading marker دارد یا خیر
 */
export function hasLoadingMarkers(content: string): boolean {
  return /\[orca\.(?:loading|image\.loading|loading\.image)\.start\]/.test(
    content
  );
}

/**
 * استخراج style برای دکمه‌های outlined
 */
export function getOutlinedButtonStyle(color?: string): Record<string, string> {
  if (!color) return {};
  const hexColor = getVuetifyColor(color);
  return {
    border: `1px solid ${hexColor}`,
    color: hexColor,
    "background-color": "transparent",
  };
}

/**
 * استخراج style برای متن دکمه‌های outlined
 */
export function getOutlinedButtonTextStyle(
  color?: string
): Record<string, string> {
  if (!color) return {};
  const hexColor = getVuetifyColor(color);
  return {
    color: hexColor,
    "background-color": "transparent",
  };
}

/**
 * استخراج style برای آیکون append
 */
export function getAppendIconStyle(color?: string): Record<string, string> {
  if (!color) return {};
  const hexColor = getVuetifyColor(color);
  return {
    color: hexColor,
    fill: hexColor,
  };
}
