<template>
  <div class="orca-location-container">
    <div class="map-wrapper">
      <div
        :ref="(el) => onMapContainerReady(el)"
        class="map-container"
        :key="`map-${latitude}-${longitude}`"
      />
    </div>
    <div class="location-info">
      <div class="location-icon">
        <svg
          width="16"
          height="16"
          viewBox="0 0 24 24"
          fill="none"
          stroke="currentColor"
          stroke-width="2"
        >
          <path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z" />
          <circle cx="12" cy="10" r="3" />
        </svg>
      </div>
      <span class="location-text">
        {{ latitude.toFixed(6) }}, {{ longitude.toFixed(6) }}
      </span>
    </div>
  </div>
</template>

<script setup lang="ts">
import { nextTick, onUnmounted, ref, type ComponentPublicInstance } from "vue";
import mapboxgl from "mapbox-gl";
import "mapbox-gl/dist/mapbox-gl.css";

/**
 * OrcaLocation - Renders map/location content using Mapbox GL JS
 * Displays interactive map with marker and navigation controls
 */
const props = defineProps<{
  latitude: number;
  longitude: number;
  mapboxToken?: string;
}>();

const mapInstance = ref<mapboxgl.Map | null>(null);
const mapLoading = ref(false);

const onMapContainerReady = (el: Element | ComponentPublicInstance | null) => {
  const htmlEl = el && "tagName" in el ? (el as HTMLElement) : null;
  if (!htmlEl) return;
  if (!el) return;

  mapLoading.value = true;

  nextTick(() => {
    try {
      // Mapbox token - can be passed as prop or from env
      mapboxgl.accessToken =
        props.mapboxToken ||
        "pk.eyJ1IjoicG91cnlhYnpwIiwiYSI6ImNsZ3Vuanl4YzF2NXkzZW1tcnR0MTlxNXEifQ.I3RdtfiL0ObnXbWVKxW1gQ";

      // Remove existing map if any
      if (mapInstance.value) {
        mapInstance.value.remove();
        mapInstance.value = null;
      }

      const containerId = `map-${props.latitude}-${props.longitude}`;
      htmlEl.id = containerId;

      const newMap = new mapboxgl.Map({
        container: htmlEl,
        style: "mapbox://styles/mapbox/streets-v11",
        center: [props.longitude, props.latitude],
        zoom: 12,
        attributionControl: false,
      });

      mapInstance.value = newMap;

      newMap.on("load", () => {
        new mapboxgl.Marker({
          color: "#0D5FD6",
        })
          .setLngLat([props.longitude, props.latitude])
          .addTo(newMap);

        newMap.addControl(new mapboxgl.NavigationControl());

        setTimeout(() => {
          newMap.resize();
        }, 100);

        mapLoading.value = false;
      });

      newMap.on("error", (e) => {
        console.error("Mapbox error:", e);
        mapLoading.value = false;
      });

      newMap.on("render", () => {
        newMap.resize();
      });
    } catch (error) {
      console.error("Error initializing map:", error);
      mapLoading.value = false;
    }
  });
};

onUnmounted(() => {
  if (mapInstance.value) {
    mapInstance.value.remove();
    mapInstance.value = null;
  }
});
</script>

